const GOOGLE_FORM_URL     = 'https://docs.google.com/forms/d/e/YOUR_FORM_ID/viewform';
const WA = `https://wa.me/977XXXXXXXXXX?text=${encodeURIComponent('Hi Bhawana! I want to book an online design class.')}`;
// 🔴 import socialImg from '../assets/your-design.jpg'; const SOCIAL_IMAGE = socialImg;
const SOCIAL_IMAGE = null;

const TOPICS=['Logo Design (Illustrator)','Social Media Post Design (Photoshop)','UI Design (Figma)','Web Design (Figma)','App Design (Figma)','Branding & Identity','Brochure Design (InDesign)','Product Design (Figma)','Other — mention in notes'];
const INIT={name:'',email:'',phone:'',topic:TOPICS[0],date:'',platform:'Discord',note:''};

export default function Learn(){
  const [form,setForm]=useState(INIT);
  const [status,setStatus]=useState('idle');
  const [err,setErr]=useState('');
  const [plat,setPlat]=useState('Discord');

  useEffect(()=>{
    const sc=document.createElement('script');
    sc.src='https://cdn.jsdelivr.net/npm/@emailjs/browser@4/dist/email.min.js';
    sc.onload=()=>window.emailjs?.init(EMAILJS_PUBLIC_KEY);
    document.head.appendChild(sc);
  },[]);

  const chg=e=>setForm(f=>({...f,[e.target.name]:e.target.value}));
  const pp=p=>{setPlat(p);setForm(f=>({...f,platform:p}))};

  const submit=async e=>{
    e.preventDefault();
    if(!form.name.trim()){setErr('Please enter your name.');return}
    if(!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)){setErr('Enter a valid email.');return}
    if(!form.phone.trim()){setErr('Enter your WhatsApp number.');return}
    if(!form.date){setErr('Select a preferred date.');return}
    setErr('');setStatus('sending');
    try{
      if(!window.emailjs)throw new Error('not ready');
      await window.emailjs.send(EMAILJS_SERVICE_ID,EMAILJS_TEMPLATE_ID,{from_name:form.name,from_email:form.email,phone:form.phone,topic:form.topic,date:form.date,platform:form.platform,note:form.note||'—',reply_to:form.email});
      setStatus('success');setForm(INIT);setPlat('Discord');
    }catch{setStatus('error');setErr('Something went wrong. Please try the Google Form below.');}
  };

  return(
    <section className={`sec ${s.sec}`} id="learn">
      <div className={s.bg} aria-hidden="true"/>
      <div className="wrap">
        <div className={s.topHead}>
          <span className="label">Online Classes</span>
          <h2 className="h2">Learn with <span className="g">Bhawana</span></h2>
          <p className={s.topDesc}>One-on-one graphic design &amp; UI design classes. Discord or Google Meet. I'll confirm your slot by email within 24 hours.</p>
        </div>

        <div className={s.grid}>
          {/* LEFT */}
          <div className={s.left}>
            {/* Preview */}
            <div className={`glass ${s.preview}`}>
              {SOCIAL_IMAGE
                ? <img src={SOCIAL_IMAGE} alt="Social Media Design" className={s.prevImg}/>
                : <div className={s.prevMock}>
                    <svg width="40" height="40" viewBox="0 0 40 40" fill="none"><rect x="2" y="5" width="36" height="26" rx="4" stroke="#aaff00" strokeWidth="1.5" fill="rgba(170,255,0,0.06)"/><circle cx="12" cy="15" r="4" fill="rgba(170,255,0,0.2)"/><path d="M2 27 L12 17 L19 22 L26 15 L38 27" stroke="#aaff00" strokeWidth="1.3" fill="none" strokeOpacity=".5"/></svg>
                    <p className={s.prevHint}>Add your social media design image here</p>
                  </div>
              }
              <div className={s.prevFoot}>
                <span className={s.prevTitle}>Social Media Post Design</span>
                <span className={s.prevTool}>Photoshop</span>
              </div>
            </div>

            {/* Class info */}
            <div className={`glass ${s.info}`}>
              <div className={s.infoHead}>
                <div className={s.infoIcon}><svg width="18" height="18" viewBox="0 0 24 24" fill="none"><circle cx="12" cy="12" r="9" stroke="#aaff00" strokeWidth="1.5"/><path d="M12 7v5l3 3" stroke="#aaff00" strokeWidth="1.5" strokeLinecap="round"/></svg></div>
                <div><div className={s.infoTitle}>1-on-1 Design Class</div><div className={s.infoSub}>Personalized · Live · Interactive</div></div>
              </div>
              <div className={s.dets}>
                {[['🕗','8:00 PM – 9:30 PM','Nepal Time (NPT)'],['📅','Flexible scheduling','Book your preferred date'],['🎯','Beginner to Intermediate','All levels welcome'],['🛠','Tools','Photoshop · Illustrator · Figma'],['📧','Email Confirmation','Within 24 hours']].map(([ic,st,sp])=>(
                  <div key={st} className={s.det}><span>{ic}</span><div><strong>{st}</strong><span>{sp}</span></div></div>
                ))}
              </div>
              <div className={s.platWrap}>
                <p className={s.platLbl}>Platform:</p>

              </div>
              <a href={GOOGLE_FORM_URL} target="_blank" rel="noreferrer" className={s.gfBtn}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><path d="M19 3H5a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2V5a2 2 0 00-2-2zm-7 3a1 1 0 110 2 1 1 0 010-2zm-4 0a1 1 0 110 2 1 1 0 010-2zm8 0a1 1 0 110 2 1 1 0 010-2zM5 19V9h14v10H5z"/></svg>
                Book via Google Form ↗
              </a>
              <div className={s.waTip}>Or message me on <a href={WA} target="_blank" rel="noreferrer" className={s.waLnk}>WhatsApp ↗</a></div>
            </div>
          </div>

          {/* RIGHT — Form */}
          <div className={`glass ${s.formCard}`}>
            <div className={s.fHead}>
              <h3 className="h3">Book Your Class Slot</h3>
              <span className={s.badge}>📧 Email confirmation</span>
            </div>
            {status==='success'&&<div className={s.ok}>✅ Booking received! Email confirmation within 24 hours.</div>}
            {err&&<div className={s.er}>{err}</div>}
            <form onSubmit={submit} noValidate>
              <div className={s.f}><label>Full Name *</label><input type="text" name="name" placeholder="Your full name" value={form.name} onChange={chg} required/></div>
              <div className={s.row}>
                <div className={s.f}><label>Email *</label><input type="email" name="email" placeholder="your@email.com" value={form.email} onChange={chg} required/></div>
                <div className={s.f}><label>WhatsApp *</label><input type="text" name="phone" placeholder="+977 98XXXXXXXX" value={form.phone} onChange={chg} required/></div>
              </div>
              <div className={s.f}><label>What to learn? *</label><select name="topic" value={form.topic} onChange={chg}>{TOPICS.map(t=><option key={t}>{t}</option>)}</select></div>
              <div className={s.row}>
                <div className={s.f}><label>Preferred Date *</label><input type="date" name="date" value={form.date} onChange={chg} required min={new Date().toISOString().split('T')[0]}/></div>
                <div className={s.f}><label>Platform</label><select name="platform" value={form.platform} onChange={chg}><option>Discord</option><option>Google Meet</option></select></div>
              </div>
              <div className={s.f}><label>Notes <span className={s.opt}>(optional)</span></label><textarea name="note" placeholder="Your experience level, questions..." value={form.note} onChange={chg}/></div>
              <button type="submit" className={s.sub} disabled={status==='sending'}>
                {status==='sending'?<><span className={s.spin}/> Sending…</>:<>Send Booking Request →</>}
              </button>
              <p className={s.nt}>Session: <strong>8:00–9:30 PM NPT</strong> · Email confirmation within 24 hrs.</p>
            </form>
          </div>
        </div>
      </div>
    </section>
  );
}
